diff --git a/src/test/java/com/fasterxml/jackson/databind/views/UnwrappedViewBypass6060Test.java b/src/test/java/com/fasterxml/jackson/databind/views/UnwrappedViewBypass6060Test.java
new file mode 100644
index 0000000000..bd52dd49fe
--- /dev/null
+++ b/src/test/java/com/fasterxml/jackson/databind/views/UnwrappedViewBypass6060Test.java
@@ -0,0 +1,117 @@
+package com.fasterxml.jackson.databind.views;
+
+import com.fasterxml.jackson.annotation.*;
+import com.fasterxml.jackson.databind.ObjectMapper;
+import com.fasterxml.jackson.databind.testutil.DatabindTestUtil;
+import org.junit.jupiter.api.Test;
+
+import static org.junit.jupiter.api.Assertions.assertEquals;
+import static org.junit.jupiter.api.Assertions.assertNotNull;
+import static org.junit.jupiter.api.Assertions.assertNull;
+
+// [databind#6060]: `@JsonView` by-passed for `@JsonUnwrapped` Field/Setter properties
+public class UnwrappedViewBypass6060Test extends DatabindTestUtil {
+    public static class PublicView {}
+    public static class AdminView extends PublicView {}
+
+    public static class AccountFlags {       // admin-only block
+        public String role;
+        public boolean approved;
+        public long creditBalance;
+    }
+    public static class Registration {       // bound at the public registration endpoint
+        @JsonView(PublicView.class) public String email;
+        @JsonView(PublicView.class) public String password;
+        @JsonView(AdminView.class) @JsonUnwrapped public AccountFlags flags;   // admin-only, unwrapped
+    }
+    public static class Control {            // identical block, NOT unwrapped
+        @JsonView(PublicView.class) public String email;
+        @JsonView(AdminView.class)  public AccountFlags flags;
+    }
+
+    public static class RegistrationWithSetters {   // same as Registration, but via setters
+        String email;
+        String password;
+        AccountFlags flags;
+
+        @JsonView(PublicView.class)
+        public void setEmail(String email) { this.email = email; }
+
+        @JsonView(PublicView.class)
+        public void setPassword(String password) { this.password = password; }
+
+        @JsonView(AdminView.class) @JsonUnwrapped
+        public void setFlags(AccountFlags flags) { this.flags = flags; }
+    }
+
+    @Test
+    void testUnwrappedBypass() throws Exception {
+        ObjectMapper mapper = sharedMapper();
+
+        String jsonC = a2q("{'email':'e','flags':{'role':'ADMIN','approved':true,'creditBalance':1000000}}");
+        Control c = mapper.readerWithView(PublicView.class)
+                .forType(Control.class)
+                .readValue(jsonC);
+        assertEquals("e", c.email);
+        assertNull(c.flags, "expected control flag to be null in PublicView read");
+
+        String jsonR = a2q("{'email':'mallory@evil.test','password':'pw',"
+                + "'role':'ADMIN','approved':true,'creditBalance':1000000}");
+        Registration r = mapper.readerWithView(PublicView.class)
+                .forType(Registration.class)
+                .readValue(jsonR);
+        assertEquals("mallory@evil.test", r.email);
+        assertEquals("pw", r.password);
+        // JsonUnwrapped flag in Registration class may affect this
+        assertNull(r.flags, "expected registration flag to be null in PublicView read");
+    }
+
+    // Negative control: AdminView read MUST populate the unwrapped admin-only block,
+    // so the PublicView assertion above is not passing vacuously.
+    @Test
+    void testUnwrappedVisibleInAdminView() throws Exception {
+        ObjectMapper mapper = sharedMapper();
+
+        String jsonR = a2q("{'email':'admin@corp.test','password':'pw',"
+                + "'role':'ADMIN','approved':true,'creditBalance':1000000}");
+        Registration r = mapper.readerWithView(AdminView.class)
+                .forType(Registration.class)
+                .readValue(jsonR);
+        assertEquals("admin@corp.test", r.email);
+        assertNotNull(r.flags, "expected registration flag to be populated in AdminView read");
+        assertEquals("ADMIN", r.flags.role);
+        assertEquals(1000000, r.flags.creditBalance);
+    }
+
+    @Test
+    void testUnwrappedBypassWithSetters() throws Exception {
+        ObjectMapper mapper = sharedMapper();
+
+        String jsonR = a2q("{'email':'mallory@evil.test','password':'pw',"
+                + "'role':'ADMIN','approved':true,'creditBalance':1000000}");
+        RegistrationWithSetters r = mapper.readerWithView(PublicView.class)
+                .forType(RegistrationWithSetters.class)
+                .readValue(jsonR);
+        assertEquals("mallory@evil.test", r.email);
+        assertEquals("pw", r.password);
+        // JsonUnwrapped flag in RegistrationWithSetters class may affect this
+        assertNull(r.flags, "expected registration flag to be null in PublicView read");
+    }
+
+    // Negative control for the setter variant: AdminView read MUST populate flags.
+    @Test
+    void testUnwrappedVisibleInAdminViewWithSetters() throws Exception {
+        ObjectMapper mapper = sharedMapper();
+
+        String jsonR = a2q("{'email':'admin@corp.test','password':'pw',"
+                + "'role':'ADMIN','approved':true,'creditBalance':1000000}");
+        RegistrationWithSetters r = mapper.readerWithView(AdminView.class)
+                .forType(RegistrationWithSetters.class)
+                .readValue(jsonR);
+        assertEquals("admin@corp.test", r.email);
+        assertNotNull(r.flags, "expected registration flag to be populated in AdminView read");
+        assertEquals("ADMIN", r.flags.role);
+        assertEquals(1000000, r.flags.creditBalance);
+    }
+
+}

diff --git a/src/test/java/com/fasterxml/jackson/databind/deser/filter/IgnorePropertiesCaseInsensitive5962Test.java b/src/test/java/com/fasterxml/jackson/databind/deser/filter/IgnorePropertiesCaseInsensitive5962Test.java
new file mode 100644
index 0000000000..9da8acbe18
--- /dev/null
+++ b/src/test/java/com/fasterxml/jackson/databind/deser/filter/IgnorePropertiesCaseInsensitive5962Test.java
@@ -0,0 +1,94 @@
+package com.fasterxml.jackson.databind.deser.filter;
+
+import org.junit.jupiter.api.Test;
+
+import com.fasterxml.jackson.annotation.JsonFormat;
+import com.fasterxml.jackson.annotation.JsonIgnoreProperties;
+
+import com.fasterxml.jackson.databind.*;
+import com.fasterxml.jackson.databind.testutil.DatabindTestUtil;
+
+import static org.junit.jupiter.api.Assertions.*;
+
+/**
+ * [databind#5962]: Case-insensitive BeanPropertyMap rebuild undoes per-property
+ * {@code @JsonIgnoreProperties}.
+ *
+ * {@code BeanDeserializerBase.createContextual()} calls {@code _handleByNameInclusion()}
+ * to filter properties according to per-property {@code @JsonIgnoreProperties}, producing
+ * a contextual deserializer with the restricted {@code BeanPropertyMap}. However, the
+ * subsequent case-insensitivity block read {@code _beanProperties} (the *original*
+ * unfiltered map from {@code this}) rather than {@code contextual._beanProperties} (the
+ * filtered map). {@code withCaseInsensitivity()} then rebuilt the map from the unfiltered
+ * source, and {@code contextual.withBeanProperties(props)} overwrote the filtered map with
+ * the unfiltered one — any properties removed by {@code _handleByNameInclusion} were
+ * restored.
+ *
+ * Patch: source the case-insensitive rebuild from {@code contextual._beanProperties}.
+ */
+public class IgnorePropertiesCaseInsensitive5962Test extends DatabindTestUtil
+{
+    static class AdminDto {
+        public String adminKey = "DEFAULT";
+        public String username;
+    }
+
+    // Container that ignores "adminKey" on the AdminDto field AND enables case-insensitive matching
+    static class Container {
+        @JsonIgnoreProperties("adminKey")
+        @JsonFormat(with = JsonFormat.Feature.ACCEPT_CASE_INSENSITIVE_PROPERTIES)
+        public AdminDto admin;
+    }
+
+    // Baseline container: only @JsonIgnoreProperties, no case-insensitive format override
+    static class BaselineContainer {
+        @JsonIgnoreProperties("adminKey")
+        public AdminDto admin;
+    }
+
+    /**
+     * NEGATIVE CONTROL: without the @JsonFormat case-insensitive override, @JsonIgnoreProperties
+     * correctly suppresses adminKey on the nested AdminDto field.
+     */
+    @Test
+    public void test5962_negativeControl_withoutCaseInsensitivity() throws Exception {
+        ObjectMapper mapper = jsonMapperBuilder().build();
+        String json = "{\"admin\":{\"adminKey\":\"HACKED\",\"username\":\"alice\"}}";
+        BaselineContainer result = mapper.readValue(json, BaselineContainer.class);
+        // Without case-insensitive format, @JsonIgnoreProperties blocks adminKey
+        assertNotEquals("HACKED", result.admin.adminKey,
+                "@JsonIgnoreProperties alone (no case-insensitive format) should block adminKey");
+        assertEquals("alice", result.admin.username);
+    }
+
+    /**
+     * EXPLOIT PATH: the case-insensitive BeanPropertyMap rebuild (triggered by
+     * @JsonFormat ACCEPT_CASE_INSENSITIVE_PROPERTIES) restores the unfiltered original
+     * _beanProperties, undoing the @JsonIgnoreProperties("adminKey") exclusion.
+     * Case-insensitive matching then routes "adminKey" (or "ADMINKEY") to the setter.
+     *
+     * Security assertion: adminKey must NOT be settable via JSON when the enclosing
+     * container declares @JsonIgnoreProperties("adminKey") on the field.
+     */
+    @Test
+    public void test5962_caseInsensitiveRebuildRestoresIgnoredProperty() throws Exception {
+        ObjectMapper mapper = jsonMapperBuilder()
+                .disable(DeserializationFeature.FAIL_ON_UNKNOWN_PROPERTIES)
+                .build();
+
+        // Exact case — should be blocked by @JsonIgnoreProperties
+        String json = "{\"admin\":{\"adminKey\":\"HACKED\",\"username\":\"alice\"}}";
+        Container result = mapper.readValue(json, Container.class);
+        assertNotEquals("HACKED", result.admin.adminKey,
+                "[databind#5962]: case-insensitive BeanPropertyMap rebuild restored 'adminKey' " +
+                        "after it was removed by @JsonIgnoreProperties. The property was set to 'HACKED'.");
+        assertEquals("alice", result.admin.username);
+
+        // Mixed case — exploits the case-insensitive rebuild more directly
+        String jsonMixed = "{\"admin\":{\"AdminKey\":\"HACKED2\",\"username\":\"bob\"}}";
+        Container result2 = mapper.readValue(jsonMixed, Container.class);
+        assertNotEquals("HACKED2", result2.admin.adminKey,
+                "[databind#5962]: 'AdminKey' (mixed case) matched 'adminKey' via case-insensitive " +
+                        "lookup that was rebuilt from the unfiltered property map.");
+    }
+}
